// Stage 27demo-m — stripe test link pipe flags (no $env)
const inbound = $input.first().json;
return [{
  json: {
    ...inbound,
    stripe_test_link_pipe_mode: true,
    demo_phone_number_id: '1152900101233109'
  }
}];

// Stage 27demo-m — normalize Meta inbound + optional booking refs
const DEMO_PHONE_NUMBER_ID = '1152900101233109';
const raw = $input.first().json;
const body = raw.body || raw;

const entry = body.entry && body.entry[0];
const change = entry && entry.changes && entry.changes[0];
const value = (change && change.value) || body;
const metadata = value.metadata || {};
const messages = value.messages || [];
const msg = messages[0] || {};
const contacts = value.contacts || [];
const profile = (contacts[0] && contacts[0].profile) || {};

const phoneNumberId = String(metadata.phone_number_id || body.phone_number_id || DEMO_PHONE_NUMBER_ID).trim();
const fromRaw = String(msg.from || body.from || body.guest_phone || body.phone || '').trim();
const guestPhone = fromRaw ? (fromRaw.startsWith('+') ? fromRaw : `+${fromRaw}`) : '';
const waMessageId = String(msg.id || body.wamid || body.inbound_message_id || '').trim() || null;

let messageText = String(
  (msg.text && msg.text.body)
    || (msg.button && msg.button.text)
    || body.message_text || body.text || body.message || ''
).trim();
if (!messageText && msg.type && msg.type !== 'text') {
  messageText = `[non-text message: ${msg.type}]`;
}

const ts = msg.timestamp || body.timestamp || null;
const receivedAt = body.received_at || (ts ? new Date(Number(ts) * 1000).toISOString() : new Date().toISOString());
const contactName = String(profile.name || body.contact_name || body.guest_name || '').trim() || null;
const guestContext = body.guest_context && typeof body.guest_context === 'object' ? body.guest_context : null;
const referenceDate = body.reference_date != null ? String(body.reference_date).trim() : '2026-06-08';
const bookingCode = body.booking_code != null ? String(body.booking_code).trim() : null;
const paymentDraftId = body.payment_draft_id != null ? String(body.payment_draft_id).trim() : null;
const bookingId = body.booking_id != null ? String(body.booking_id).trim() : null;

if (!guestPhone) throw new Error('Missing guest_phone');
if (!messageText) throw new Error('Missing message_text');
if (!waMessageId) throw new Error('Missing wamid');

return [{
  json: {
    source: 'n8n_open_demo_whatsapp_inbound',
    client_slug: String(body.client_slug || 'wolfhouse-somo').trim(),
    channel: 'whatsapp',
    phone_number_id: phoneNumberId,
    guest_phone: guestPhone,
    message_text: messageText,
    wamid: waMessageId,
    inbound_message_id: waMessageId,
    received_at: receivedAt,
    contact_name: contactName,
    raw_meta_message_id: waMessageId,
    guest_context: guestContext,
    reference_date: referenceDate,
    booking_code: bookingCode,
    booking_id: bookingId,
    payment_draft_id: paymentDraftId,
    stripe_test_link_pipe_mode: true
  }
}];
